    );
  test_core_data_in_rsci_inst_data_in_rsc_dat <= data_in_rsc_dat;
  data_in_rsci_idat_mxwt <= test_core_data_in_rsci_inst_data_in_rsci_idat_mxwt;

  test_core_coeffs_rsci_1_inst : test_core_coeffs_rsci_1
    PORT MAP(
      clk => clk,
